args.sparql:
SELECT ?athlete ?athleteLabel ?medal ?medalLabel
WHERE {
  ?event wdt:P1517 wd:Q38807566 ;
         wdt:P649 wd:Q171875 ;
         wdt:P1992 wd:Q6581072 .
  ?athlete p:P3763 ?ms.
  ?ms pq:P1517 ?event.
  ?ms pq:P1392 ?medal.
  ?athlete rdfs:label ?athleteLabel . FILTER (LANG(?athleteLabel) = "en")
  ?medal rdfs:label ?medalLabel . FILTER (LANG(?medalLabel) = "en")
}

SELECT ?athlete ?athleteLabel ?medal ?medalLabel
WHERE {
  ?event wdt:P585 "2018-02-25"^^xsd:date ;
         wdt:P1326 wd:Q1078929 .
  ?athlete p:P3763 ?statement .
  ?statement pq:P1517 ?event .
  ?statement pq:P1392 ?medal .
  ?athlete rdfs:label ?athleteLabel . FILTER (LANG(?athleteLabel) = "en")
  ?medal rdfs:label ?medalLabel . FILTER (LANG(?medalLabel) = "en")
}
